module portfolio_optimizer (
    input [7:0] stock1,
    input [7:0] stock2,
    input [7:0] stock3,
    input [7:0] stock4,
    input [7:0] stock5,
    output reg [7:0] obf_max_return
);

always @(*) begin
    obf_max_return = stock1; // Initialize with the first stock
    if (stock2 > obf_max_return) obf_max_return = stock2;
    if (stock3 > obf_max_return) obf_max_return = stock3;
    if (stock4 > obf_max_return) obf_max_return = stock4;
    if (stock5 > obf_max_return) obf_max_return = stock5;
end

endmodule
